//vip.opstream16.com/share/000cb7efa8a05429dd5309b4bea2eb0c","link_m3u8":"https://vip.opstream16.com/20230323/33363_f20a683f/index.m3u8"},{"name":"18","slug":"18","filename":"TVB Xin Chào Thầy 18⧸20 ｜ tiếng Việt ｜ Lê Minh, Tuyên Huyên, Lý Ỷ Hồng ｜ TVB 1994","link_embed":"https://vip.opstream16.com/share/00498fd626d602ffabe6acc9636155b7","link_m3u8":"https://vip.opstream16.com/20230323/33364_68a2a97e/index.m3u8"},{"name":"19","slug":"19","filename":"TVB Xin Chào Thầy 19⧸20 ｜ tiếng Việt ｜ Lê Minh, Tuyên Huyên, Lý Ỷ Hồng ｜ TVB 1994","link_embed":"https://vip.opstream16.com/share/ebbef3b7bea693ae9aa25f2885a828cc","link_m3u8":"https://vip.opstream16.com/20230323/33365_8024a4cc/index.m3u8"},{"name":"20","slug":"20","filename":"TVB Xin Chào Thầy 20⧸20 ｜ tiếng Việt ｜ Lê Minh, Tuyên Huyên, Lý Ỷ Hồng ｜ TVB 1994","link_embed":"https://vip.opstream16.com/share/1ce018a9cf7f2480f079ce6bdd49af8a","link_m3u8":"https://vip.opstream16.com/20230323/33366_5073aa8f/index.m3u8"}]}],"time":"45 phút/tập","description":"<p>Chúc Đại Bảo (Lê Minh đóng) sau khi làm việc trong ngành quảng cáo nhưng anh gặp nhiều khó khăn đâm ra thất chí, đã được hồng nhan tri kỉ (Tuyên Huyên đóng) giới thiệu đến 1 trường học, đảm nhận vai trò 1 thầy giáo đứng lớp. Tại trường học Bảo đã quen được Phương Đồng Tâm-một nữ giáo viên(Lý Ỷ Hồng đóng), cô ấy đã làm cho anh hiểu rằng cần đặc biệt quan tâm đến những học sinh bướng bỉnh, phải có thái độ dạy học tận tình, tận tụy. ban đầu Bảo gặp nhều khó khăn khi tiếp cận với học sinh nhưng bằng sự chân thành của mình bảo đã dần dần chiếm được cảm tình và lòng tin của các em học sinh, và rất được học sinh yêu quý, tuy mỗi em một hoàn cảnh, một tính cách nhưng tình cảm của chúng đối với anh là hoàn toàn chân thành. Bạn gái của Bảo vì tham hư vinh mà nỡ bỏ anh ra đi, khiến anh rất đau lòng. Trong quá trình dạy học, Chúc Đại Bảo đã nảy sinh lòng cảm mến đối với Phương Đồng Tâm, đáng tiếc, cô ấy sớm đã có bạn trai là Lục Kiến Tài (Cổ thiên Lạc đóng). Sau đó Tâm Di lại đem lòng ái mộ Chúc Đại Bảo, CHúc Đại Bảo vốn rất khéo léo tinh tế trong chuyện tình cảm nam nữ, nhưng cũng hok biết phải lựa chọn thế nào. Ở mặt khác, cha của Chúc Đại Bảo (Hoàng Chiêm đóng) tự cho mình là người phong lưu, nên đã khiến cho mẹ của Chúc Đại Bảo phải ra ở riêng, còn cậu của anh (La Gia Anh đóng) thường xuyên đấu khẩu với bà nội của anh (Hạ Bình đóg), 1 gia đình mà mọi người lun cãi nhau như thế nàykhiến Chúc Đại bảo vô cùng nhức đầu.</p>","tmdb":{"type":"tv","id":"94916","season":1,"vote_average":0,"vote_count":0},"modified":"2024-12-11T14:31:34.000Z","_image_preserved":true},{"id":"641d960383982600241e3499","_id":"641d960383982600241e3499","title":"Chúng ta đang chạy trốn ai vậy mẹ?","origin_name":"Who Were We Running From?","slug":"chung-ta-dang-chay-tron-ai-vay-me","year":2023,"type":"series","genre":[{"id":"620a2249e0fc277084dfd2e5","name":"Hình Sự","slug":"hinh-su"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"},{"id":"620f84d291fa4af90ab6b3f4","name":"Bí ẩn","slug":"bi-an"}],"country":[{"id":"620f7fa791fa4af90ab6ad1f","name":"Thổ Nhĩ Kỳ","slug":"tho-nhi-ky"}],"lang_key":"Vietsub","episode_current":"Hoàn tất (7/7)","quality":"FHD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"1","slug":"1","filename":"Chúng ta đang chạy trốn ai vậy mẹ__S01E01_Tập 1","link_embed":"https://vip.opstream14.com/share/e64a2afffe539dbd117ce1499a1883b6","link_m3u8":"https://vip.opstream14.com/20230324/34083_359d3945/index.m3u8"},{"name":"2","slug":"2","filename":"Chúng ta đang chạy trốn ai vậy mẹ__S01E02_Tập 2","link_embed":"https://vip.opstream14.com/share/248fc25e78dfd13c7f22da88e4b79924","link_m3u8":"https://vip.opstream14.com/20230324/34084_d773b1a9/index.m3u8"},{"name":"3","slug":"3","filename":"Chúng ta đang chạy trốn ai vậy mẹ__S01E03_Tập 3","link_embed":"https://vip.opstream14.com/share/4bfc7637274e584b77